import React from 'react';
import { Card, Stack, Divider } from '@ggui-ai/design/primitives';
import { Text, Heading } from '@ggui-ai/design/primitives';

interface Props {
  /** City name */
  city: string;
  /** Current temperature */
  temperature: number;
  /** Weather condition (Sunny, Cloudy, Rainy, etc.) */
  condition: string;
  /** Humidity percentage */
  humidity: number;
  /** Wind speed */
  windSpeed: number;
  /** Temperature unit (C or F) */
  unit?: string;
  /** 5-day forecast array */
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>;
}

export default function GeneratedComponent(props: Props) {
  const {
    city = 'Unknown City',
    temperature = 0,
    condition = '--',
    humidity = 0,
    windSpeed = 0,
    unit = 'C',
    forecast = [],
  } = props;

  return (
    <Card shadow="md" padding={24} radius="lg">
      <Stack gap={16}>
        <Stack gap={4}>
          <Heading level={3}>{city}</Heading>
          <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
            {condition}
          </Text>
        </Stack>

        <Text size="4xl" weight="bold">
          {temperature}°{unit}
        </Text>

        <Stack direction="horizontal" gap={16}>
          <Text variant="bodySmall">
            Humidity: <span style={{ fontWeight: 600 }}>{humidity}%</span>
          </Text>
          <Text variant="bodySmall">
            Wind: <span style={{ fontWeight: 600 }}>{windSpeed} km/h</span>
          </Text>
        </Stack>

        <Divider margin={8} />

        <Stack direction="horizontal" justify="between" align="center">
          {forecast.map((item, idx) => (
            <Stack key={idx} align="center" gap={4}>
              <Text variant="label">{item.day ?? 'Day'}</Text>
              <Text size="xl">{item.icon ?? '?'}</Text>
              <Text variant="bodySmall">
                {item.high ?? 0}°/{item.low ?? 0}°
              </Text>
            </Stack>
          ))}
        </Stack>
      </Stack>
    </Card>
  );
}

import React, { useState, useEffect } from 'react';
import {
  Container,
  Card,
  Stack,
  Heading,
  Text,
  Button,
  Divider,
  Progress,
  Box
} from '@ggui-ai/design/primitives';
import {
  Input,
  TextArea,
  RadioGroup,
  Checkbox,
  FormField
} from '@ggui-ai/design/components';

interface Props {
  featureOptions: string[];
  satisfactionLabels: string[];
  onSubmit?: (data: {
    name: string;
    email: string;
    satisfaction: number;
    features: string[];
    comments: string;
  }) => void;
}

export default function GeneratedComponent(props: Props) {
  const [step, setStep] = useState(1);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [formData, setFormData] = useState({
    name: '',
    email: '',
    satisfaction: -1,
    features: [] as string[],
    comments: ''
  });
  const [errors, setErrors] = useState({ name: '', email: '', satisfaction: '' });

  useEffect(() => {
    const handleAgentData = (event: any) => {
      console.log('Agent Data Received:', event.detail);
    };
    window.addEventListener('ggui:agent-data', handleAgentData);
    return () => window.removeEventListener('ggui:agent-data', handleAgentData);
  }, []);

  const validateStep = (current: number): boolean => {
    let isValid = true;
    const newErrors = { name: '', email: '', satisfaction: '' };

    if (current === 1) {
      if (!formData.name.trim()) {
        newErrors.name = 'Name is required';
        isValid = false;
      }
      if (!/\S+@\S+\.\S+/.test(formData.email)) {
        newErrors.email = 'Valid email is required';
        isValid = false;
      }
    } else if (current === 2) {
      if (formData.satisfaction === -1) {
        newErrors.satisfaction = 'Please select a rating';
        isValid = false;
      }
    }
    setErrors(newErrors);
    return isValid;
  };

  const handleNext = () => { if (validateStep(step)) setStep((s) => s + 1); };
  const handleBack = () => setStep((s) => Math.max(1, s - 1));

  const submitForm = () => {
    setIsSubmitting(true);
    props.onSubmit?.(formData);
    setTimeout(() => setIsSubmitting(false), 1000);
  };

  return (
    <Container maxWidth="sm" padding="var(--ggui-spacing-6)">
      <Card shadow="md" padding="var(--ggui-spacing-6)" radius="lg">
        <Stack gap="var(--ggui-spacing-6)">
          <Stack gap="var(--ggui-spacing-2)">
            <Text variant="label">Step {step} of 4</Text>
            <Progress value={step} max={4} variant="default" size="md" />
          </Stack>

          {step === 1 && (
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={3}>Your Information</Heading>
              <FormField label="Full Name" error={errors.name} required>
                <Input label="Full Name" value={formData.name} onChange={(v) => setFormData(p => ({ ...p, name: v }))} />
              </FormField>
              <FormField label="Email" error={errors.email} required>
                <Input label="Email" type="email" value={formData.email} onChange={(v) => setFormData(p => ({ ...p, email: v }))} />
              </FormField>
            </Stack>
          )}

          {step === 2 && (
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={3}>Satisfaction Rating</Heading>
              <RadioGroup
                label="How satisfied are you?"
                value={formData.satisfaction === -1 ? '' : formData.satisfaction.toString()}
                onChange={(v) => setFormData(p => ({ ...p, satisfaction: parseInt(v) }))}
                options={props.satisfactionLabels.map((l, i) => ({ value: i.toString(), label: l }))}
                error={errors.satisfaction}
              />
            </Stack>
          )}

          {step === 3 && (
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={3}>Interests</Heading>
              {props.featureOptions.map(f => (
                <Checkbox
                  key={f}
                  label={f}
                  checked={formData.features.includes(f)}
                  onChange={(checked) => setFormData(p => ({ 
                    ...p, 
                    features: checked ? [...p.features, f] : p.features.filter(x => x !== f) 
                  }))}
                />
              ))}
            </Stack>
          )}

          {step === 4 && (
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={3}>Final Review</Heading>
              <Box background="var(--ggui-color-surfaceVariant)" padding="var(--ggui-spacing-4)" borderRadius="var(--ggui-shape-radius-md)">
                <Stack gap="var(--ggui-spacing-1)">
                  <Text variant="label">Name: {formData.name}</Text>
                  <Text variant="label">Email: {formData.email}</Text>
                  <Text variant="label">Rating: {props.satisfactionLabels[formData.satisfaction] ?? 'N/A'}</Text>
                  <Text variant="label">Features: {formData.features.length > 0 ? formData.features.join(', ') : 'None'}</Text>
                </Stack>
              </Box>
              <Divider />
              <TextArea
                label="Comments"
                value={formData.comments}
                onChange={(v) => setFormData(p => ({ ...p, comments: v }))}
                maxLength={500}
                showCount
              />
            </Stack>
          )}

          <Stack direction="horizontal" gap="var(--ggui-spacing-2)" justify="between">
            <Button variant="secondary" onClick={handleBack} disabled={step === 1}>Back</Button>
            {step < 4 ? (
              <Button onClick={handleNext}>Next</Button>
            ) : (
              <Button onClick={submitForm} loading={isSubmitting}>Submit Survey</Button>
            )}
          </Stack>
        </Stack>
      </Card>
    </Container>
  );
}

import React, { useState, useEffect } from 'react';
import {
  Container,
  Stack,
  Card,
  Text,
  Heading,
  Box,
  Divider,
  Button,
  Input,
  Select,
  Badge,
  Avatar,
  Spacer,
} from '@ggui-ai/design/primitives';

interface Props {
  tasks: Array<{
    id?: string;
    title?: string;
    priority?: 'low' | 'medium' | 'high';
    assignee?: string;
    column?: string;
    dueDate?: string;
  }>;
  columns: Array<{ id?: string; name?: string }>;
  onTaskUpdate?: (payload: {
    action: 'move' | 'edit' | 'create';
    taskId: string;
    data: any;
  }) => void;
}

export default function GeneratedComponent(props: Props) {
  const [tasks, setTasks] = useState(props.tasks ?? []);
  const [addingToColumn, setAddingToColumn] = useState<string | null>(null);
  const [newTask, setNewTask] = useState({
    title: '',
    priority: 'medium' as 'low' | 'medium' | 'high',
  });

  useEffect(() => {
    setTasks(props.tasks ?? []);
  }, [props.tasks]);

  useEffect(() => {
    const handleAgentData = (event: any) => {
      const detail = event.detail;
      if (detail && detail.id) {
        setTasks((prev) => [...prev, detail]);
      }
    };
    window.addEventListener('ggui:agent-data', handleAgentData);
    return () => window.removeEventListener('ggui:agent-data', handleAgentData);
  }, []);

  const handleTaskUpdate = (
    action: 'move' | 'edit' | 'create',
    taskId: string,
    data: any
  ) => {
    if (action === 'create') {
      const createdTask = {
        ...data,
        id: Date.now().toString(),
        column: addingToColumn,
      };
      setTasks((prev) => [...prev, createdTask]);
      props.onTaskUpdate?.({ action, taskId: createdTask.id, data: createdTask });
      setAddingToColumn(null);
      setNewTask({ title: '', priority: 'medium' });
    } else {
      setTasks((prev) =>
        prev.map((t) => (t.id === taskId ? { ...t, ...data } : t))
      );
      props.onTaskUpdate?.({ action, taskId, data });
    }
  };

  const getBadgeVariant = (priority?: string) => {
    switch (priority) {
      case 'high':
        return 'error';
      case 'medium':
        return 'warning';
      default:
        return 'info';
    }
  };

  const completedCount = tasks.filter((t) => t.column === 'done').length;

  return (
    <Container maxWidth="full" padding="var(--ggui-spacing-6, 24px)">
      <Stack gap="var(--ggui-spacing-4, 16px)">
        <Card padding="var(--ggui-spacing-6, 24px)" border={true} radius="md">
          <Stack direction="horizontal" justify="between" align="center">
            <Heading level={2}>Project Task Board</Heading>
            <Stack direction="horizontal" gap="var(--ggui-spacing-4, 16px)">
              <Text variant="label">Total Tasks: {tasks.length}</Text>
              <Text variant="label" color="var(--ggui-color-success, #16a34a)">
                Completed: {completedCount}
              </Text>
            </Stack>
          </Stack>
        </Card>

        <Stack
          direction="horizontal"
          gap="var(--ggui-spacing-4, 16px)"
          align="start"
          wrap={true}
        >
          {(props.columns ?? []).map((col) => {
            const colTasks = tasks.filter((t) => t.column === col.id);
            return (
              <Box
                key={col.id}
                background="var(--ggui-color-surfaceVariant, #f4f4f5)"
                padding="var(--ggui-spacing-4, 16px)"
                borderRadius="var(--ggui-shape-radius-md, 8px)"
                style={{ minWidth: '300px', flex: 1 }}
              >
                <Stack gap="var(--ggui-spacing-4, 16px)">
                  <Heading level={4}>
                    {col.name} ({colTasks.length})
                  </Heading>
                  {colTasks.map((task) => (
                    <Card
                      key={task.id}
                      padding="var(--ggui-spacing-4, 16px)"
                      shadow="sm"
                      border={true}
                      radius="md"
                    >
                      <Stack gap="var(--ggui-spacing-2, 8px)">
                        <Text variant="label">{task.title}</Text>
                        <Stack
                          direction="horizontal"
                          gap="var(--ggui-spacing-2, 8px)"
                          align="center"
                        >
                          <Badge
                            variant={getBadgeVariant(task.priority)}
                            size="sm"
                          >
                            {task.priority ?? 'medium'}
                          </Badge>
                          {task.assignee && (
                            <Avatar name={task.assignee} size={24} />
                          )}
                          {task.dueDate && (
                            <Text variant="caption">{task.dueDate}</Text>
                          )}
                        </Stack>
                        <Divider margin="var(--ggui-spacing-2, 8px)" />
                        <Select
                          label="Move to"
                          value={task.column ?? ''}
                          onChange={(val) =>
                            handleTaskUpdate('move', task.id!, { column: val })
                          }
                          options={(props.columns ?? []).map((c) => ({
                            value: c.id!,
                            label: c.name!,
                          }))}
                        />
                      </Stack>
                    </Card>
                  ))}
                  {addingToColumn === col.id ? (
                    <Card
                      padding="var(--ggui-spacing-4, 16px)"
                      border={true}
                      shadow="md"
                    >
                      <Stack gap="var(--ggui-spacing-2, 8px)">
                        <Input
                          label="Title"
                          value={newTask.title}
                          onChange={(val) =>
                            setNewTask({ ...newTask, title: val })
                          }
                        />
                        <Select
                          label="Priority"
                          value={newTask.priority}
                          onChange={(val) =>
                            setNewTask({
                              ...newTask,
                              priority: val as 'low' | 'medium' | 'high',
                            })
                          }
                          options={[
                            { value: 'low', label: 'Low' },
                            { value: 'medium', label: 'Medium' },
                            { value: 'high', label: 'High' },
                          ]}
                        />
                        <Stack
                          direction="horizontal"
                          gap="var(--ggui-spacing-2, 8px)"
                        >
                          <Button
                            size="sm"
                            onClick={() =>
                              handleTaskUpdate('create', '', newTask)
                            }
                          >
                            Save
                          </Button>
                          <Button
                            size="sm"
                            variant="ghost"
                            onClick={() => setAddingToColumn(null)}
                          >
                            Cancel
                          </Button>
                        </Stack>
                      </Stack>
                    </Card>
                  ) : (
                    <Button
                      variant="outline"
                      size="sm"
                      onClick={() => setAddingToColumn(col.id!)}
                    >
                      + Add Task
                    </Button>
                  )}
                </Stack>
              </Box>
            );
          })}
        </Stack>
      </Stack>
    </Container>
  );
}

import React, { useState, useMemo } from 'react';
import { Container, Stack, Box, Card, Text, Heading, Input } from '@ggui-ai/design/primitives';

interface ElementData {
  atomicNumber?: number;
  symbol?: string;
  name?: string;
  atomicWeight?: number;
  category?: string;
  row?: number;
  col?: number;
}

interface Props {
  elements: ElementData[];
}

const CATEGORY_COLORS: Record<string, string> = {
  'noble-gas': 'var(--ggui-color-info-100, #cffafe)',
  'halogen': 'var(--ggui-color-warning-100, #fef3c7)',
  'nonmetal': 'var(--ggui-color-success-100, #dcfce7)',
  'alkali-metal': 'var(--ggui-color-primary-100, #e0f2fe)',
};

export default function GeneratedComponent(props: Props) {
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedElement, setSelectedElement] = useState<ElementData | null>(null);

  const filteredElements = useMemo(() => {
    const q = searchQuery.toLowerCase();
    return props.elements.map((el) => ({
      ...el,
      isDimmed:
        searchQuery.length > 0 &&
        !(
          el.name?.toLowerCase().includes(q) ||
          el.symbol?.toLowerCase().includes(q)
        ),
    }));
  }, [props.elements, searchQuery]);

  const categories = Array.from(new Set(props.elements.map((e) => e.category || 'other')));

  return (
    <Container maxWidth="full" padding="var(--ggui-spacing-8, 32px)">
      <Stack gap="var(--ggui-spacing-8, 32px)">
        <Stack gap="var(--ggui-spacing-4, 16px)">
          <Heading level={1}>Periodic Table</Heading>
          <Input
            label="Search Elements"
            placeholder="Search by name or symbol..."
            value={searchQuery}
            onChange={(val) => setSearchQuery(val)}
            type="search"
          />
        </Stack>

        <Box
          style={{
            display: 'grid',
            gridTemplateColumns: 'repeat(18, 1fr)',
            gap: 'var(--ggui-spacing-1, 4px)',
            role: 'grid',
          }}
        >
          {filteredElements.map((el) => (
            <Box
              key={el.atomicNumber}
              style={{
                gridColumnStart: el.col,
                gridRowStart: el.row,
                background: el.isDimmed
                  ? 'var(--ggui-color-surfaceVariant, #f4f4f5)'
                  : (CATEGORY_COLORS[el.category || ''] ?? 'var(--ggui-color-surfaceVariant, #f4f4f5)'),
                opacity: el.isDimmed ? 0.3 : 1,
                cursor: 'pointer',
                border: '1px solid var(--ggui-color-outlineVariant, #e4e4e7)',
                borderRadius: 'var(--ggui-shape-radius-sm, 4px)',
                padding: 'var(--ggui-spacing-2, 8px)',
                display: 'flex',
                flexDirection: 'column',
                justifyContent: 'space-between',
                aspectRatio: '1',
                transition: 'opacity 200ms ease',
              }}
              onClick={() => setSelectedElement(el)}
              role="gridcell"
              aria-label={`${el.name}, atomic number ${el.atomicNumber}`}
            >
              <Text variant="caption">{el.atomicNumber}</Text>
              <Text variant="bodyLarge" weight="bold" align="center">{el.symbol}</Text>
            </Box>
          ))}
        </Box>

        <Stack direction="horizontal" gap="var(--ggui-spacing-4, 16px)" wrap>
          {categories.map((cat) => (
            <Stack key={cat} direction="horizontal" gap="var(--ggui-spacing-2, 8px)" align="center">
              <Box
                style={{
                  width: 'var(--ggui-spacing-4, 16px)',
                  height: 'var(--ggui-spacing-4, 16px)',
                  background: CATEGORY_COLORS[cat] ?? 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                  borderRadius: 'var(--ggui-shape-radius-sm, 4px)',
                }}
              />
              <Text variant="caption">{cat}</Text>
            </Stack>
          ))}
        </Stack>

        {selectedElement && (
          <Card padding="var(--ggui-spacing-6, 24px)" radius="lg">
            <Stack gap="var(--ggui-spacing-2, 8px)">
              <Heading level={3}>
                {selectedElement.name} ({selectedElement.symbol})
              </Heading>
              <Text variant="body">Atomic Number: {selectedElement.atomicNumber}</Text>
              <Text variant="body">Atomic Weight: {selectedElement.atomicWeight}</Text>
              <Text variant="label">Category: {selectedElement.category}</Text>
            </Stack>
          </Card>
        )}
      </Stack>
    </Container>
  );
}

import React, { useState, useEffect, useRef } from 'react';
import { Card, Stack, Box, Text, Heading, Input, Button, Badge, Divider } from '@ggui-ai/design/primitives';

interface Props {
  /** Chat window title */
  title: string;
  /** Current user name (for right-aligning own messages) */
  currentUser: string;
  /** Number of participants */
  participantCount?: number;
  /** Array of messages with sender name, text, and ISO timestamp */
  messages: Array<{ sender?: string; text?: string; timestamp?: string }>;
  /** Callback for sending messages */
  onSendMessage?: (payload: { text: string; timestamp: string }) => void;
}

export default function GeneratedComponent(props: Props) {
  const [inputText, setInputText] = useState('');
  const [messages, setMessages] = useState(props.messages);
  const scrollEndRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    scrollEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages]);

  useEffect(() => {
    const handleIncoming = (event: any) => {
      const data = event.detail;
      if (data?.text) {
        setMessages((prev) => [...prev, data]);
      }
    };
    window.addEventListener('ggui:agent-data', handleIncoming);
    return () => window.removeEventListener('ggui:agent-data', handleIncoming);
  }, []);

  const handleSend = () => {
    if (!inputText.trim()) return;
    const timestamp = new Date().toISOString();
    const payload = { text: inputText, timestamp };

    props.onSendMessage?.(payload);
    setMessages((prev) => [...prev, { sender: props.currentUser, ...payload }]);
    setInputText('');
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter') handleSend();
  };

  return (
    <Card 
      shadow="md" 
      radius="lg"
      style={{ 
        width: '100%', 
        height: '600px', 
        display: 'flex', 
        flexDirection: 'column', 
        overflow: 'hidden' 
      }}
    >
      <Stack 
        direction="horizontal" 
        align="center" 
        justify="between"
        style={{ 
          padding: 'var(--ggui-spacing-4)', 
          borderBottom: '1px solid var(--ggui-color-outlineVariant)' 
        }}
      >
        <Heading level={3}>{props.title}</Heading>
        {props.participantCount !== undefined && (
          <Badge variant="secondary" pill={true}>{props.participantCount} participants</Badge>
        )}
      </Stack>

      <Box style={{ flex: 1, overflowY: 'auto', padding: 'var(--ggui-spacing-4)' }}>
        <Stack gap={16} aria-live="polite">
          {messages.map((msg, idx) => {
            const isOwn = msg.sender === props.currentUser;
            const prevMsg = messages[idx - 1];
            const showSender = idx === 0 || prevMsg.sender !== msg.sender;

            return (
              <Stack key={idx} align={isOwn ? 'end' : 'start'} gap={4}>
                {showSender && !isOwn && (
                  <Text variant="caption" style={{ paddingLeft: 'var(--ggui-spacing-1)' }}>
                    {msg.sender ?? 'Unknown'}
                  </Text>
                )}
                <Box
                  paddingX={12}
                  paddingY={8}
                  borderRadius={12}
                  background={isOwn ? 'var(--ggui-color-primary-600)' : 'var(--ggui-color-surfaceVariant)'}
                >
                  <Text color={isOwn ? '#ffffff' : 'var(--ggui-color-onSurface)'}>
                    {msg.text}
                  </Text>
                </Box>
                {msg.timestamp && (
                  <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                    {new Date(msg.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                  </Text>
                )}
              </Stack>
            );
          })}
          <div ref={scrollEndRef} />
        </Stack>
      </Box>

      <Stack 
        direction="horizontal" 
        gap={8} 
        align="center"
        style={{ 
          padding: 'var(--ggui-spacing-4)', 
          borderTop: '1px solid var(--ggui-color-outlineVariant)' 
        }}
      >
        <div style={{ flex: 1 }}>
          <Input
            label="Message"
            placeholder="Type a message..."
            value={inputText}
            onChange={(val) => setInputText(val)}
            onKeyDown={handleKeyDown}
          />
        </div>
        <Button 
          variant="primary" 
          onClick={handleSend} 
          disabled={!inputText.trim()}
          aria-label="Send message"
        >
          Send
        </Button>
      </Stack>
    </Card>
  );
}

import React, { useState, useEffect } from 'react';
import { Container, Stack, Box, Card, Text, Heading, Icon } from '@ggui-ai/design/primitives';
import { CardGrid } from '@ggui-ai/design/compositions';

interface Props {
  /** Array of stocks with symbol, name, price, change, changePercent */
  stocks: Array<{ 
    symbol?: string; 
    name?: string; 
    price?: number; 
    change?: number; 
    changePercent?: number 
  }>;
  /** ISO timestamp of last price update */
  lastUpdated?: string;
}

export default function GeneratedComponent(props: Props) {
  const [liveStocks, setLiveStocks] = useState(props.stocks);
  const [timestamp, setTimestamp] = useState(props.lastUpdated);

  useEffect(() => {
    const handleAgentData = (event: any) => {
      const detail = event.detail ?? {};
      if (detail.stocks) setLiveStocks(detail.stocks);
      if (detail.lastUpdated) setTimestamp(detail.lastUpdated);
    };

    window.addEventListener('ggui:agent-data', handleAgentData);
    return () => window.removeEventListener('ggui:agent-data', handleAgentData);
  }, []);

  return (
    <Container maxWidth="xl" padding={24}>
      <Stack gap={24}>
        <Box paddingY={16}>
          <Stack gap={8}>
            <Heading level={1}>Market Watch</Heading>
            <Text 
              variant="caption" 
              color="var(--ggui-color-onSurfaceVariant)" 
              aria-label={timestamp ? `Last updated at ${timestamp}` : 'Connecting...'}
            >
              {timestamp ? `Last Updated: ${new Date(timestamp).toLocaleTimeString()}` : 'Connecting...'}
            </Text>
          </Stack>
        </Box>

        <div aria-live="polite">
          <CardGrid columns={{ sm: 1, md: 3 }} gap={16}>
            {liveStocks.map((stock, index) => {
              const changeVal = stock.change ?? 0;
              const isPositive = changeVal >= 0;
              const color = isPositive 
                ? 'var(--ggui-color-success)' 
                : 'var(--ggui-color-error)';
              const icon = isPositive ? 'chevron-up' : 'chevron-down';

              return (
                <Card key={stock.symbol ?? index} shadow="sm" radius="md" border={true}>
                  <Stack gap={16}>
                    <Stack gap={4}>
                      <Text weight="bold" size="lg">{stock.symbol ?? 'N/A'}</Text>
                      <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                        {stock.name ?? 'Unknown'}
                      </Text>
                    </Stack>

                    <Heading level={3}>
                      ${(stock.price ?? 0).toFixed(2)}
                    </Heading>

                    <Stack direction="horizontal" gap={8} align="center">
                      <Icon name={icon} size={16} color={color} />
                      <Text 
                        weight="medium" 
                        color={color} 
                        style={{ transition: 'color 200ms ease' }}
                      >
                        {isPositive ? '▲' : '▼'} {Math.abs(changeVal).toFixed(2)} ({stock.changePercent?.toFixed(2)}%)
                      </Text>
                    </Stack>
                  </Stack>
                </Card>
              );
            })}
          </CardGrid>
        </div>
      </Stack>
    </Container>
  );
}

import React, { useState, useEffect } from 'react';
import {
  Container,
  Card,
  Stack,
  Heading,
  Text,
  Input,
  Select,
  Toggle,
  RadioGroup,
  Progress,
  Button,
  Divider,
  Box,
  Spacer
} from '@ggui-ai/design/primitives';

interface Props {
  initialProfile?: {
    name?: string;
    email?: string;
    avatar?: string;
    role?: string;
    emailNotifications?: boolean;
    theme?: string;
  };
  avatarOptions: string[];
  roleOptions: string[];
  onComplete: (data: any) => void;
}

export default function GeneratedComponent(props: Props) {
  const [step, setStep] = useState(1);
  const [data, setData] = useState({
    name: props.initialProfile?.name ?? "",
    email: props.initialProfile?.email ?? "",
    avatar: props.initialProfile?.avatar ?? props.avatarOptions[0] ?? "",
    role: props.initialProfile?.role ?? "",
    emailNotifications: props.initialProfile?.emailNotifications ?? false,
    theme: props.initialProfile?.theme ?? "light",
  });

  useEffect(() => {
    const handleAgentData = (e: any) => {
      if (e.detail) setData((prev) => ({ ...prev, ...e.detail }));
    };
    window.addEventListener('ggui:agent-data', handleAgentData as EventListener);
    return () => window.removeEventListener('ggui:agent-data', handleAgentData as EventListener);
  }, []);

  const isEmailValid = (email: string) => /\S+@\S+\.\S+/.test(email);

  const isStepValid = () => {
    if (step === 1) return data.name.trim() !== "" && isEmailValid(data.email);
    if (step === 2) return data.role !== "";
    return true;
  };

  const handleNext = () => {
    if (step < 3) setStep(step + 1);
    else props.onComplete(data);
  };

  return (
    <Container maxWidth="sm" padding={24}>
      <Card shadow="md" padding={32} radius="lg" border={true}>
        <Stack gap={16}>
          <Stack gap={8}>
            <Text variant="overline" color="var(--ggui-color-onSurfaceVariant)">Step {step} of 3</Text>
            <Progress value={(step / 3) * 100} variant="default" size="md" />
          </Stack>

          <div style={{ animation: 'ggui-fadeIn 200ms ease-out', minHeight: '320px' }} aria-live="polite">
            {step === 1 && (
              <Stack gap={16}>
                <Heading level={3}>Profile Setup</Heading>
                <Input label="Name" value={data.name} onChange={(val) => setData({ ...data, name: val })} required />
                <Input label="Email" type="email" value={data.email} onChange={(val) => setData({ ...data, email: val })} required />
                <RadioGroup
                  label="Choose your Avatar"
                  value={data.avatar}
                  onChange={(val) => setData({ ...data, avatar: val })}
                  direction="horizontal"
                  options={props.avatarOptions.map((a) => ({ value: a, label: a }))}
                />
              </Stack>
            )}

            {step === 2 && (
              <Stack gap={16}>
                <Heading level={3}>Preferences</Heading>
                <Select
                  label="Role"
                  value={data.role}
                  onChange={(val) => setData({ ...data, role: val })}
                  options={props.roleOptions.map((r) => ({ value: r, label: r }))}
                  placeholder="Select a role"
                  required
                />
                <Toggle label="Email notifications" checked={data.emailNotifications} onChange={(val) => setData({ ...data, emailNotifications: val })} />
                <Toggle label="Dark theme" checked={data.theme === 'dark'} onChange={(val) => setData({ ...data, theme: val ? 'dark' : 'light' })} />
              </Stack>
            )}

            {step === 3 && (
              <Stack gap={16}>
                <Heading level={3}>Review & Confirm</Heading>
                <Box background="var(--ggui-color-surfaceVariant)" padding={16} borderRadius={8}>
                  <Stack gap={8}>
                    <Text variant="label">Name: {data.name}</Text>
                    <Text variant="label">Email: {data.email}</Text>
                    <Text variant="label">Role: {data.role}</Text>
                    <Text variant="label">Avatar: {data.avatar}</Text>
                    <Text variant="label">Notifications: {data.emailNotifications ? 'Enabled' : 'Disabled'}</Text>
                    <Text variant="label">Theme: {data.theme}</Text>
                  </Stack>
                </Box>
              </Stack>
            )}
          </div>

          <Divider margin={16} />

          <Stack direction="horizontal" gap={16} justify="between">
            <Button variant="ghost" disabled={step === 1} onClick={() => setStep(step - 1)}>
              Back
            </Button>
            <Button disabled={!isStepValid()} onClick={handleNext}>
              {step === 3 ? "Complete Setup" : "Next"}
            </Button>
          </Stack>
        </Stack>
      </Card>
    </Container>
  );
}
